queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?civil_engineers a :Civil_Engineers .
    ?civil_engineers p:name ?name .
    ?civil_engineers p:design_software_expertise ?design_software_expertise_f .
    FILTER(STR(?design_software_expertise_f) = "AutoCAD")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?architects a :Architects .
    ?architects p:name ?name .
    ?architects p:design_software_expertise ?design_software_expertise_f .
    FILTER(STR(?design_software_expertise_f) = "AutoCAD")
    BIND(?name AS ?o0)
  }
}

